const input = $input.first().json;
const binaryData = $input.first().binary;

let channel = 'webhook';
let content = '';
let contact_name = 'Unknown';

if (input.source === 'audio') {
  channel = 'audio';

  // Whisper returns text nested in data field
  let transcription = '';
  if (typeof input.data === 'string') {
    transcription = input.data;
  } else if (input.text) {
    transcription = input.text;
  } else if (input.transcription) {
    transcription = input.transcription;
  }
  content = transcription;

  const nameMatch = transcription.match(/my name is ([\w]+ [\w]+)/i) ||
                    transcription.match(/mein Name ist ([\w]+ [\w]+)/i) ||
                    transcription.match(/I(?:'m| am) ([\w]+ [\w]+)/i) ||
                    transcription.match(/this is ([\w]+ [\w]+)/i);
  contact_name = nameMatch ? nameMatch[1] : 'Caller (unknown)';
} else if (input.subject || input.from) {
  channel = 'email';
  content = input.text || input.html || '';

  // Try to extract name from From header e.g. "Maria Fischer <maria@example.com>"
  const fromRaw = input.from?.text || input.from || '';
  const nameMatch = fromRaw.match(/^"?([^"<]+)"?\s*</);
  if (nameMatch) {
    contact_name = nameMatch[1].trim();
  } else {
    // Fall back to email address if no name found
    contact_name = fromRaw.replace(/<.*>/, '').trim() || fromRaw;
  }
} else {
  channel = 'webhook';
  content = input.message || input.content || JSON.stringify(input);
  contact_name = input.body?.name || input.name || input.customer || 'Unknown';
}

return [{
  json: {
    channel,
    contact_name,
    content,
    received_at: new Date().toISOString(),
    raw: input
  }
}];

const inputData = $input.first().json;

let parsed;
try {
  const raw = inputData.response || inputData.text || '';
  const cleaned = raw.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    summary: 'Could not parse response',
    sentiment: 'normal',
    has_todo: false,
    is_critical: false
  };
}

// Walk back through previous nodes to find normalizer data
const normalizer = $node["Normalizer"].json;

return [{
  json: {
    channel: normalizer.channel || 'webhook',
    contact_name: normalizer.contact_name || 'Unknown',
    content: normalizer.content || '',
    received_at: normalizer.received_at || new Date().toISOString(),
    summary: parsed.summary || '',
    sentiment: parsed.sentiment || 'normal',
    has_todo: parsed.has_todo === true,
    is_critical: parsed.is_critical === true
  }
}];

const content = $input.first().json.content;

const response = await this.helpers.request({
  method: 'POST',
  url: 'http://ollama:11434/api/generate',
  headers: {
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    model: 'mistral',
    stream: false,
    prompt: `Du bist ein Kundenservice-Analyst für ein Möbelhaus. Analysiere den folgenden Kundenkontakt und antworte NUR mit einem gültigen JSON-Objekt, ohne Erklärung, ohne Markdown, ohne zusätzlichen Text.

Gib genau diese Struktur zurück:
{"summary": "2-3 Satz Zusammenfassung", "sentiment": "gut", "has_todo": false, "is_critical": false}

Regeln:
- sentiment muss exakt eines sein: gut, normal, schlecht
- has_todo ist true wenn der Kunde einen Rückruf oder eine Nachverfolgung benötigt
- is_critical ist true wenn der Kunde sehr verärgert oder dringend ist
- Antworte auf Deutsch

Kundenkontakt:
${content}`
  })
});

const parsed = typeof response === 'string' ? JSON.parse(response) : response;

return [{ json: { response: parsed.response } }];

